    // Calculate next power of two
    let n = hashes.len() as u64;
    let target = 1_u64.checked_pow(n.ilog2()) * (if n % 2 == 0 { 1 } else { 2 }); // Simplified logic

    // Better approach: use standard padding logic
    let padded_len = if hashes.len() == 0 { 0 } else {
